{
  "pattern": {
    "summary": "Recognize boolean combinations where one side is a singleton equality/inequality compare against a constant A and the other side is a masked compare of the same X against constant B using a negative power-of-2 mask M, where the masked compare denotes an aligned contiguous interval. Convert the masked compare into its implied ConstantRange and then fold with the singleton compare using existing range reasoning.",
    "applicable_boolean_forms": [
      {
        "root_op": "or",
        "cmp_predicates": [
          "icmp eq",
          "icmp eq"
        ],
        "meaning": "union of ranges"
      },
      {
        "root_op": "and",
        "cmp_predicates": [
          "icmp ne",
          "icmp ne"
        ],
        "meaning": "intersection of complements, equivalent to complement of union"
      }
    ],
    "match_shape": [
      "(icmp eq/ne X, A)  OR/AND  (icmp eq/ne (and X, M), B)",
      "(icmp eq/ne A, X)  OR/AND  (icmp eq/ne B, (and X, M))",
      "either compare may appear on either side of the boolean op"
    ],
    "requirements": [
      "M is a negative power-of-2 mask, i.e. clears the low k bits and keeps the upper bits",
      "the and has one use",
      "A and B are constants of the same integer type as X",
      "A and B differ by exactly 1",
      "A+1 or B+1, as appropriate for adjacency, is a power of 2",
      "that power of 2 is at least abs(M)",
      "the singleton compare constant is exactly adjacent to the aligned interval represented by the masked compare, so the union is contiguous"
    ],
    "range_interpretation": {
      "masked_eq": "(X & M) == B denotes X in [B, B + abs(M) - 1]",
      "masked_ne": "(X & M) != B denotes X notin [B, B + abs(M) - 1]",
      "canonical_interval_formula": "For negative power-of-2 mask M and masked-equality constant C, interpret as ConstantRange(C, C - M). Since M < 0, C - M = C + abs(M)."
    },
    "canonical_examples": [
      {
        "source": "(x == 127) || ((x & -32) == 128)",
        "intervals": [
          "x == 127 => {127}",
          "(x & -32) == 128 => [128,160)"
        ],
        "folded": "x-127 u< 33"
      },
      {
        "source": "(x != 127) && ((x & -32) != 128)",
        "intervals": [
          "complement of {127}",
          "complement of [128,160)"
        ],
        "folded": "x-127 u>= 33"
      }
    ],
    "implementation_notes": [
      "This belongs in foldAndOrOfICmpsUsingRanges().",
      "When one compare is a plain singleton region and the other is a masked compare with a negative power-of-2 mask, widen the masked compare from a singleton exact-value region to the aligned interval implied by the mask before attempting range combination.",
      "Support operand commutation in both the icmps and the top-level boolean op.",
      "Only positive cases are listed below; non-applicable cases include non-negated-power-of-2 masks, constants not adjacent, disjoint unions, and multi-use and operands."
    ]
  },
